import{_ as e,c as o,o as s,ak as d,aY as t,aZ as i,a_ as r,a$ as l,b0 as c,b1 as n,b2 as _,b3 as h,b4 as p,b5 as m,b6 as b,b7 as g,b8 as S}from"./chunks/framework.C7_z9xNE.js";const v=JSON.parse('{"title":"基础使用","description":"正确使用ETS2LA","frontmatter":{"title":"基础使用","description":"正确使用ETS2LA","layout":"doc"},"headers":[],"relativePath":"version/v3/docs/base/use.md","filePath":"version/v3/docs/base/use.md"}'),k={name:"version/v3/docs/base/use.md"};function f(T,a,u,x,A,P){return s(),o("div",null,[...a[0]||(a[0]=[d('<h1 id="基础使用" tabindex="-1">基础使用 <a class="header-anchor" href="#基础使用" aria-label="Permalink to “基础使用”">​</a></h1><div class="tip custom-block"><p class="custom-block-title">提醒</p><p>目前不支持中文 请等待后续支持</p></div><h3 id="_1-新手引导" tabindex="-1">1. 新手引导 <a class="header-anchor" href="#_1-新手引导" aria-label="Permalink to “1. 新手引导”">​</a></h3><p>第一次打开软件你会遇见以下情况 <img src="'+t+'" alt="" loading="lazy"> 点击键盘上<code>右边的Alt</code>按键并点击<code>ShowMessage</code>以来关闭</p><video controls width="640"><source src="'+i+'" type="video/mp4"> 您的浏览器不支持播放视频。 </video><h3 id="sdk-install" tabindex="-1">2. 安装sdk <a class="header-anchor" href="#sdk-install" aria-label="Permalink to “2. 安装sdk”">​</a></h3><p>依次在软件里点击 <code>Settings</code>-<code>SDK</code>-<code>点击当前版本你要安装的SDK</code><img src="'+r+'" alt="" loading="lazy"> 当你看见这个时 代表安装成功 <img src="'+l+'" alt="" loading="lazy"></p><h3 id="_3-安装插件" tabindex="-1">3. 安装插件 <a class="header-anchor" href="#_3-安装插件" aria-label="Permalink to “3. 安装插件”">​</a></h3><p>依次在软件里点击 <code>Catalogue</code>-<code>刷新</code>-<code>把刷新后显示的6个插件都点上(制作教程时只有这么多)</code><img src="'+c+'" alt="" loading="lazy"> 点击Restart ETS2LA 并等待ETS2LA重启 <img src="'+n+'" alt="" loading="lazy"> ETS2LA重启后 点击<code>Manager</code>把4个插件启动(制作教程时只有这么多) <img src="'+_+'" alt="" loading="lazy"></p><h3 id="_4-覆盖层" tabindex="-1">4. 覆盖层 <a class="header-anchor" href="#_4-覆盖层" aria-label="Permalink to “4. 覆盖层”">​</a></h3><p>如果觉得这些内容碍眼可以点击键盘上<code>右边的Alt</code>按键进行调整与关闭 <img src="'+h+'" alt="" loading="lazy"><img src="'+p+'" alt="" loading="lazy"></p><h2 id="_5-按键更改" tabindex="-1">5. 按键更改 <a class="header-anchor" href="#_5-按键更改" aria-label="Permalink to “5. 按键更改”">​</a></h2><p>由于ETS2LA默认使用同一个按键来控制自动转向与自动油门 但这样可能会导致启动了自动油门但是自动转向无法使用的问题 所以我们建议你更改控制按键 依次在软件里点击 <code>Settings</code>-<code>Controls</code>-<code>分别点击Assist和SET/OK</code>修改你想要使用的按键(尽量不要使用和游戏冲突的按键) <img src="'+m+'" alt="" loading="lazy"></p><h2 id="_6-更新" tabindex="-1">6. 更新 <a class="header-anchor" href="#_6-更新" aria-label="Permalink to “6. 更新”">​</a></h2><p>由于软件仍在开发中，所以及时更新软件就显得极为重要，ETS2LA的更新总共分为四总方式，分别为软件内和软件外</p><h3 id="_6-1-软件内" tabindex="-1">6.1 软件内 <a class="header-anchor" href="#_6-1-软件内" aria-label="Permalink to “6.1 软件内”">​</a></h3><h4 id="_6-1-1-检测到更新" tabindex="-1">6.1.1 检测到更新 <a class="header-anchor" href="#_6-1-1-检测到更新" aria-label="Permalink to “6.1.1 检测到更新”">​</a></h4><p>点击软件<code>Settings</code>-<code>Updates</code>，然后在加载出来的页面点击<code>Install and Restart</code><img src="'+b+'" alt="" loading="lazy"></p><h4 id="_6-1-2-未检测到更新" tabindex="-1">6.1.2 未检测到更新 <a class="header-anchor" href="#_6-1-2-未检测到更新" aria-label="Permalink to “6.1.2 未检测到更新”">​</a></h4><p>如果作者发布了新的版本 但是在加载ETS2LA时没有检测到 可以点击软件<code>Settings</code>-<code>Updates</code>，然后在加载出来的页面点击<code>Check for Updates</code>等待重新检测 如有可以点击<code>Install and Restart</code>进行更新 <img src="'+g+'" alt="" loading="lazy"></p><h3 id="_6-2-软件外" tabindex="-1">6.2 软件外 <a class="header-anchor" href="#_6-2-软件外" aria-label="Permalink to “6.2 软件外”">​</a></h3><p>打开你的ETS2LA安装目录（如果不知道并且在桌面创建了快捷方式的可以右键<code>打开文件所在位置</code>）找到<code>update.exe</code>这个文件并双击运行即可触发更新进程 <img src="'+S+'" alt="" loading="lazy"></p>',22)])])}const z=e(k,[["render",f]]);export{v as __pageData,z as default};
